+            .allocator = allocator,
+            .breakpoints = std.ArrayList(Breakpoint).init(allocator),
+            .bp_by_file = std.StringHashMap(std.ArrayList(usize)).init(allocator),
+            .next_bp_number = 1,
+            .stop_here = false,
+            .return_frame = null,
+            .stop_reason = null,
+            .skip = null,
+            .stopframe = null,
+            .returnframe = null,
+            .quitting = false,
+            .curframe = null,
+            .curindex = 0,
+            .stack = std.ArrayList(*FrameInfo).init(allocator),
+            .on_stop = null,
+            .on_breakpoint = null,
+        };
+    }
+
+    pub fn deinit(self: *Self) void {
+        self.breakpoints.deinit();
+
+        var it = self.bp_by_file.iterator();
+        while (it.next()) |entry| {
+            entry.value_ptr.deinit();
+        }
+        self.bp_by_file.deinit();
+
+        self.stack.deinit();
+    }
+
+    /// Reset the debugger state
+    pub fn reset(self: *Self) void {
+        self.stop_here = false;
+        self.return_frame = null;
+        self.stop_reason = null;
+        self.stopframe = null;
+        self.returnframe = null;
+        self.quitting = false;
+    }
+
+    // ========================================================================
+    // Breakpoint Management
+    // ========================================================================
+
+    /// Set a breakpoint
+    pub fn setBreak(
+        self: *Self,
+        filename: []const u8,
+        lineno: usize,
+        temporary: bool,
+        cond: ?[]const u8,
+        funcname: ?[]const u8,
+    ) !*Breakpoint {
